/* =====================================================================
   EMBEDDED SKB MAPPING  (v2.0 — generated by generate_skb_mapping.py)
===================================================================== */
function getEmbeddedMap(){
  return (S&&S.activeMode==='SKA')?SKA_MAP:SKB_MAP;
}
function txKey(canonical){ return (S.activeMode||'SKB')+':'+canonical; }

function setMode(mode){
  if(S.activeMode===mode) return;
  S.activeMode=mode;

  // Update toggle buttons
  ['SKA','SKB'].forEach(m=>{
    const btn=id('modeBtn-'+m);
    if(btn) btn.classList.toggle('mode-btn-active', m===mode);
  });

  // Show/hide CC-Matrix section (SKB only)
  const ccSec=id('ccMatrixSection');
  if(ccSec) ccSec.style.display=mode==='SKB'?'':'none';

  // Clear active mapping so embedded map for new mode is used
  S.activeMapping=null;

  // Bug fix: clear stale COA side cache from a previous run in the other mode
  S._coaSideMap=null;

  // Bug fix: remove dynamically-added second key column rows (added by addKeyCol during SKB).
  // Without this, SKB's "Company Code" second key col remains in the DOM when switching to SKA
  // and runDiff() picks it up, forming composite keys in SKA mode and producing wrong results.
  TX_SOURCES.forEach(src=>{
    const extraRow=id('keyRow'+src+'1');
    if(extraRow && extraRow.classList.contains('key-row-extra')){
      extraRow.remove();
      const btn=id('btnAddKey'+src); if(btn) btn.style.display='flex';
      const sr=id('sepRow'+src);     if(sr)  sr.style.display='none';
    }
  });
  // Reset key field selections so buildKeySelects auto-resolves fresh for the new mode
  S.keyFields={COA:'', FAQ:'', DataPool:''};

  // Preserve uploaded transactional files (FAQ, DataPool) and COA Master —
  // they are the same for SKA and SKB. Only clear derived diff state.
  // CC-Matrix is SKB-only: clear it when switching to SKA.
  if(mode==='SKA'){
    S.refWbs.CC_MATRIX=null;
    S.refFns.CC_MATRIX='';
    S.ccMatrixOE='SERE';
    const dr=id('ref-drop-CC_MATRIX');
    if(dr) dr.classList.remove('loaded');
    const fn=id('ref-fn-CC_MATRIX');
    if(fn){fn.textContent='';fn.classList.add('hidden');}
    const oeSelect=id('ccMatrixOESelect');
    if(oeSelect) oeSelect.value='SERE';
  }

  // Clear diff results and derived state — NOT uploaded files
  // NOTE: S.fieldTransforms is intentionally NOT cleared here.
  // txKey() namespaces every entry as "SKA:<canonical>" or "SKB:<canonical>",
  // so SKA and SKB transforms are fully isolated. Wiping on mode switch would
  // permanently destroy the inactive mode's transforms in localStorage.
  S.resolvedMap=[];
  S.comparableFields=[];
  S._diffRows=[];
  S._coaSideMap=null;
  S.hiddenCols=new Set();
  id('mapTbody').innerHTML='';
  // Reset only dynamic result content — never wipe the structural HTML
  const sg=id('summaryGrid'); if(sg) sg.innerHTML='';
  const sm=id('summaryMode'); if(sm) sm.textContent='';
  const cs=id('coaStats');    if(cs) cs.innerHTML='';
  const diffOut=id('diffOut');
  if(diffOut) diffOut.innerHTML='<div class="empty"><div class="empty-ico">&#128269;</div><h3>No comparison yet</h3><p>Upload files, review the mapping, then click Run Compare.</p></div>';
  S.diffCounts={same:0,conflict:0,onlyCOA:0,onlyFAQ:0,onlyDP:0,total:0,noReference:0,unexpectedCoco:0};

  // Bug fix: clear agent history and SQLite table — both are mode-specific.
  // Stale SKA conversation + schema in _rdmHistory would mislead the agent in SKB mode
  // (and vice versa). The SQLite diff_results table has mode-specific columns, so it
  // must also be dropped to prevent stale SQL results before a new comparison is run.
  clearRDM();
  if(_sqlReady&&_diffDb){try{_diffDb.run('DROP TABLE IF EXISTS diff_results');}catch(e){}}
  updateRdmDbBadge(0);
  setStep(1);

  // Update header badge
  const badge=id('hdrModeBadge');
  if(badge) badge.textContent=mode;

  checkReady();
  showToast('Switched to '+mode+' mode','ok');
}

