/* =====================================================================
   UTILITIES
===================================================================== */
function id(x){return document.getElementById(x);}
function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function normalise(s){return s.toLowerCase().replace(/\s+/g,' ').trim().replace(/[^a-z0-9 ]/g,'');}

function similarity(a,b){
  const na=normalise(a), nb=normalise(b);
  if(na===nb) return 1;
  if(na.replace(/ /g,'')=== nb.replace(/ /g,'')) return 0.97;
  if(na.includes(nb)||nb.includes(na)) return 0.88;
  const wa=new Set(na.split(' ')), wb=new Set(nb.split(' '));
  const inter=[...wa].filter(w=>wb.has(w)).length;
  const union=new Set([...wa,...wb]).size;
  const j=union>0?inter/union:0;
  if(j>=0.5) return 0.7+j*0.2;
  let m=0;
  for(let i=0;i<Math.min(na.length,nb.length);i++) if(na[i]===nb[i]) m++;
  return m/Math.max(na.length,nb.length,1);
}

function findBestCol(jsonCol, headers){
  if(!jsonCol||!headers.length) return null;
  // Tier 1: exact raw match
  if(headers.includes(jsonCol)) return jsonCol;
  // Tier 2: normalised exact match — handles trailing newlines, casing, extra spaces
  const n = normHdr(jsonCol);
  const normExact = headers.find(h => normHdr(h) === n);
  if(normExact) return normExact;
  // Tier 3: starts-with — handles "(New) To be updated..." suffixes in file headers
  const normPrefix = headers.find(h => normHdr(h).startsWith(n + ' ') || normHdr(h).startsWith(n + '('));
  if(normPrefix) return normPrefix;
  // Tier 4: fuzzy similarity
  let best=null, bestScore=0;
  headers.forEach(h=>{
    const s=similarity(jsonCol,h);
    if(s>bestScore){bestScore=s;best=h;}
  });
  return bestScore>=0.55?best:null;
}

function showToast(msg, type){
  const t=id('toast');
  t.textContent=msg;
  t.className='toast show '+(type||'ok');
  clearTimeout(t._to);
  t._to=setTimeout(()=>{t.className='toast';},3000);
}

function showProgress(title,sub){
  id('progTitle').textContent=title;
  id('progSub').textContent=sub||'';
  id('progOverlay').classList.remove('hidden');
}
function hideProgress(){id('progOverlay').classList.add('hidden');}

function setStep(n){showTab(n);} // legacy shim

/* =====================================================================
   TAB + SUB-TAB NAVIGATION
===================================================================== */
let _activeSubTab='settings';

function showTab(n){
  [1,2,3].forEach(i=>{
    const btn=id('tab-btn-'+i), panel=id('tab-panel-'+i);
    if(btn) btn.classList.toggle('active',i===n);
    if(btn) btn.classList.toggle('done',i<n);
    if(btn) btn.classList.toggle('enabled',true);
    if(panel) panel.classList.toggle('active',i===n);
  });
  // Full viewport width on Compare tab, constrained on Upload/Mapping
  const canvas=document.querySelector('.canvas');
  if(canvas) canvas.classList.toggle('canvas-wide', n===3);
  if(n===2){
    SOURCES.forEach(src=>{if(S.wbs[src])extractHeaders(src);});
    if(!S.resolvedMap.length) buildResolvedMap();
    renderMappingTable(); refreshMapMeta();
    const ci=id('caseSensitive'); if(ci) ci.checked=S.caseSensitive;
    const tww=id('togTrimWrap');     if(tww) tww.classList.toggle('on',S.trimWhitespace);
    const ciw=id('togCaseWrap');     if(ciw) ciw.classList.toggle('on',S.caseSensitive);
    const stw=id('togStrikeWrap');   if(stw) stw.classList.toggle('on',S.skipStrike);
    const yw=id('togYellowWrap');    if(yw)  yw.classList.toggle('on',S.skipYellow);
    const tdw=id('togTenDigitWrap'); if(tdw) tdw.classList.toggle('on',S.skipTenDigit);
  }
  if(n===3){refreshCompareHint();buildKeySelects();showSubTab(_activeSubTab);}
}

function showSubTab(name){
  _activeSubTab=name;
  if(name==='transforms') renderTxCard();
  ['settings','transforms','results'].forEach(s=>{
    const btn=id('subtab-btn-'+s), panel=id('subtab-panel-'+s);
    if(btn) btn.classList.toggle('active',s===name);
    if(panel) panel.classList.toggle('active',s===name);
  });
}

function toggleCollapse(bodyId, iconId){
  const body=id(bodyId), icon=id(iconId);
  if(!body||!icon) return;
  const isOpen=icon.classList.contains('open');
  if(isOpen){
    body.style.maxHeight=body.scrollHeight+'px';
    requestAnimationFrame(()=>requestAnimationFrame(()=>{
      body.style.maxHeight='0';
      body.style.opacity='0';
      body.classList.add('collapsed');
      icon.classList.remove('open');
    }));
  } else {
    body.classList.remove('collapsed');
    body.style.opacity='1';
    body.style.maxHeight=body.scrollHeight+'px';
    icon.classList.add('open');
    setTimeout(()=>{body.style.maxHeight='none';},350);
  }
}

/* =====================================================================
   FILE LOADING
===================================================================== */
function dov(e,src){e.preventDefault();id('drop-'+src).classList.add('drag-over');}
function dol(src){id('drop-'+src).classList.remove('drag-over');}
function ddr(e,src){e.preventDefault();dol(src);const f=e.dataTransfer.files[0];if(f)loadFile(src,f);}

function loadFile(src,file){
  // Show blocking overlay immediately
  const srcColor={COA:'var(--coa-bg)',FAQ:'var(--faq-bg)',DataPool:'var(--dp-bg)'};
  const srcTextColor={COA:'var(--coa-text)',FAQ:'var(--faq-text)',DataPool:'var(--dp-text)'};
  const srcBadge={COA:'🌿 COA Master',FAQ:'📈 FAQ (SAP)',DataPool:'📊 DataPool'};
  id('fileLoadSrc').textContent=srcBadge[src];
  id('fileLoadSrc').style.background=srcColor[src];
  id('fileLoadSrc').style.color=srcTextColor[src];
  id('fileLoadTitle').textContent='Reading '+file.name+'…';
  id('fileLoadSub').textContent=src==='COA'
    ?'Parsing cell styles to detect yellow (hierarchy) rows'
    :'Parsing workbook…';
  id('fileLoadHint').textContent=src==='COA'
    ?'COA files with 200k+ rows may take 15–30 seconds — please wait'
    :'';
  id('fileLoadOverlay').classList.remove('hidden');

  const r=new FileReader();
  r.onload=e=>{
    setTimeout(()=>{
      const opts={type:'array',cellDates:false};
      if(src==='COA') opts.cellStyles=true;
      const wb=XLSX.read(new Uint8Array(e.target.result),opts);
      id('fileLoadTitle').textContent='Indexing worksheets…';
      id('fileLoadSub').textContent=wb.SheetNames.length+' sheet'+(wb.SheetNames.length!==1?'s':'')+ ' found';
      S.wbs[src]=wb;
      S.fns[src]=file.name;
      const sel=id('sheet-'+src);
      const wrap=id('sheet-'+src+'-wrap');
      // Populate sheet selector — always show it so user can confirm/change sheet
      sel.innerHTML=wb.SheetNames.map((s,i)=>'<option value="'+i+'">'+esc(s)+'</option>').join('');
      if(wrap) wrap.style.display = wb.SheetNames.length > 1 ? '' : 'none';
      id('fileLoadTitle').textContent='Extracting headers…';
      id('fileLoadSub').textContent='Sheet: '+wb.SheetNames[0];
      extractHeaders(src);
      if(src==='COA'){
        const shIdx=parseInt(sel.value)||0;
        S.coaWs=wb.Sheets[wb.SheetNames[shIdx]];
      }
      id('fn-'+src).textContent='📄 '+file.name;
      id('fn-'+src).classList.remove('hidden');
      id('drop-'+src).classList.add('loaded');
      S.activeSources.add(src);
      updateSourceToggle(src);
      id('fileLoadOverlay').classList.add('hidden');
      checkReady();
    },src==='COA'?80:20);
  };
  r.readAsArrayBuffer(file);
}

function onSheetChange(src){
  if(!S.wbs[src]) return;
  extractHeaders(src);
  if(src==='COA'){
    const shIdx=parseInt(id('sheet-COA').value)||0;
    S.coaWs=S.wbs.COA.Sheets[S.wbs.COA.SheetNames[shIdx]];
  }
}

function onRefSheetChange(refKey){
  // No immediate action needed — buildCoaMasterMap/buildCCMatrixData
  // read the selector value at diff time. Just show the new sheet name.
  const sel = id('sheet-' + refKey);
  const wb  = S.refWbs[refKey];
  if (!sel || !wb) return;
  const shIdx = parseInt(sel.value) || 0;
  showToast(({COA_MASTER:'COA Master', CC_MATRIX:'CC-Matrix'}[refKey]||refKey) +
    ': sheet "' + wb.SheetNames[shIdx] + '" selected', 'ok');
}

function extractHeaders(src){
  const wb=S.wbs[src];
  if(!wb) return;
  const shIdx=parseInt(id('sheet-'+src).value)||0;
  const rows=XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[shIdx]],{header:1,defval:'',raw:false});
  S.headers[src]=(rows[0]||[]).map(String);
}

function getSourceRows(src){
  if(src==='COA') return getFilteredCOARows();
  const wb=S.wbs[src];
  if(!wb) return [];
  const shIdx=parseInt(id('sheet-'+src).value)||0;
  const rows=XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[shIdx]],{header:1,defval:'',raw:false});
  return rows.slice(1).map(r=>r.map(v=>v==null?'':String(v)));
}

function updateSourceToggle(src){
  const colorKey={COA:'coa',FAQ:'faq',DataPool:'dp'};
  const resLabel={COA:'🌿 COA',FAQ:'📈 FAQ',DataPool:'📊 DataPool'};
  const loaded=!!S.wbs[src];
  const active=S.activeSources.has(src);
  const ck=colorKey[src];

  // Upload-card toggle button (div in v2)
  const btn=id('tog-'+src);
  if(btn){
    btn.classList.toggle('file-loaded',loaded);
    btn.classList.remove('active-coa','active-faq','active-dp','inactive');
    if(loaded) btn.classList.add(active?'active-'+ck:'inactive');
  }

  // Results-view compact button
  const rBtn=id('res-tog-'+src);
  if(rBtn){
    rBtn.style.display=loaded?'':'none';
    rBtn.textContent=resLabel[src];
    rBtn.className='res-src-btn';
    if(loaded) rBtn.classList.add(active?'rs-active-'+ck:'rs-inactive');
  }
}

function toggleActiveSource(src){
  if(!S.wbs[src]) return;
  const active=S.activeSources.has(src);
  // Must keep at least 2 active
  if(active&&S.activeSources.size<=2){
    showToast('Need at least 2 active sources to compare','warn');
    return;
  }
  if(active) S.activeSources.delete(src);
  else S.activeSources.add(src);
  updateSourceToggle(src);
  checkReady();
  const inResults=id('subtab-panel-results')&&id('subtab-panel-results').classList.contains('active');
  if(inResults){
    const nowActive=S.activeSources.has(src);
    showToast(SRC_LABEL[src]+' '+(nowActive?'activated \u2714':'deactivated \u2716')+' \u2014 click Re-run Compare','ok');
  }
}



/* =====================================================================
   REFERENCE FILE LOADING  (v5 new)
===================================================================== */
function loadRefFile(refKey, file) {
  if (!file) return;
  const labels = {COA_MASTER: 'COA Master', CC_MATRIX: 'CC-Matrix'};
  showProgress('Loading ' + labels[refKey] + '\u2026', file.name);
  const r = new FileReader();
  r.onload = e => {
    try {
      const opts = {type:'array', cellDates:false, raw:false};
      if(refKey === 'COA_MASTER') opts.cellStyles = true; // needed for yellow/strike row detection
      const data = new Uint8Array(e.target.result);
      const wb = XLSX.read(data, opts);
      S.refWbs[refKey] = wb;
      S.refFns[refKey] = file.name;
      // Populate sheet selector
      const sel  = id('sheet-' + refKey);
      const wrap = id('sheet-' + refKey + '-wrap');
      if (sel) {
        sel.innerHTML = wb.SheetNames.map((s,i) => '<option value="'+i+'">'+esc(s)+'</option>').join('');
        // Pre-select the sheet matching the mapping config if possible
        const mapping = S.activeMapping || getEmbeddedMap();
        const cfg = mapping.reference_files && mapping.reference_files[refKey];
        if (cfg) {
          let matchIdx = 0;
          if (cfg.data_sheet) {
            // CC-Matrix: match by sheet name
            const nameIdx = wb.SheetNames.indexOf(cfg.data_sheet);
            if (nameIdx >= 0) matchIdx = nameIdx;
          } else if (cfg.sheet_index != null) {
            matchIdx = cfg.sheet_index;
          }
          sel.value = String(matchIdx);
        }
      }
      if (wrap) wrap.style.display = wb.SheetNames.length > 1 ? '' : 'none';
      updateRefDropUI(refKey, file.name);
      hideProgress();
      showToast(labels[refKey] + ' loaded — ' + wb.SheetNames.length + ' sheet(s)', 'ok');
      checkReady();
    } catch(err) {
      hideProgress();
      showToast('Error loading ' + labels[refKey] + ': ' + err.message, 'err');
    }
  };
  r.readAsArrayBuffer(file);
}

function updateRefDropUI(refKey, fileName) {
  const drop = id('ref-drop-' + refKey);
  const fnEl = id('ref-fn-' + refKey);
  if (drop) drop.classList.add('loaded');
  if (fnEl) { fnEl.textContent = '\u2713 ' + fileName; fnEl.classList.remove('hidden'); }
}

/* =====================================================================
   READY CHECK  (v5 — CC_MATRIX required for SKB mode)
===================================================================== */
function checkReady() {
  const mapping    = S.activeMapping || getEmbeddedMap();
  const isSKB      = mapping.comparison_grain === 'account_company_code';
  const isSKA      = mapping.comparison_grain === 'gl_account';
  const txUploaded = TX_SOURCES.filter(s => S.wbs[s]);
  const ccLoaded   = !!S.refWbs.CC_MATRIX;

  const ready = isSKB
    ? (ccLoaded && txUploaded.length >= 1)
    : (txUploaded.length >= 1);  // SKA: CC-Matrix not required

  const hint = id('uploadHint');

  // Tab/button unlock
  const goBtn = id('btnGoToMapping');
  if (goBtn)  goBtn.disabled = !ready;
  const tab2btn = id('tab-btn-2');
  if (tab2btn) tab2btn.classList.toggle('enabled', ready);
  const tab3btn = id('tab-btn-3');
  if (tab3btn) tab3btn.classList.toggle('enabled', ready);

  if (ready) {
    TX_SOURCES.forEach(src => { if (S.wbs[src]) extractHeaders(src); });
    if (!S.resolvedMap.length) buildResolvedMap();
    buildKeySelects();
    refreshMapMeta();
    refreshCompareHint();
    const mt = id('mapTbody');
    if (mt && !mt.innerHTML) renderMappingTable();

    const mode = isSKB
      ? ('SKB mode \u2014 ' + txUploaded.map(s => SRC_LABEL[s]).join(' & '))
      : (txUploaded.length === 3 ? '3-way' : '2-way \u2014 ' + txUploaded.map(s => SRC_LABEL[s]).join(' \u2194 '));
    if (hint) { hint.textContent = '\u2713 Ready \u2014 ' + mode; hint.style.color = 'var(--add-src)'; }
  } else {
    let msg;
    if (isSKB && !ccLoaded)    msg = 'Upload CC-Matrix (required for SKB) + at least one of FAQ / DataPool';
    else if (txUploaded.length === 0) msg = 'Upload at least one source file (FAQ / DataPool)';
    else msg = 'Upload CC-Matrix + at least one transactional source';
    if (hint) { hint.textContent = msg; hint.style.color = 'var(--text3)'; }
  }

  // COA Master warning: if CC-Matrix is loaded but COA_MASTER is not,
  // flag that coa_lookup / coa_derived fields will show null on the COA side
  {
    const coaMasterWarn = id('coaMasterWarn');
    if (coaMasterWarn) {
      const activeMap = S.activeMapping || getEmbeddedMap();
      const needsCoaMaster = activeMap.fields
        .some(f => f.sources && f.sources.COA && (f.type === 'coa_lookup' || f.type === 'coa_derived'));
      const missing = needsCoaMaster && !S.refWbs.COA_MASTER;
      coaMasterWarn.style.display = missing ? 'inline-flex' : 'none';
      // Update warn text to list affected fields for current mode
      if (missing) {
        const affectedFields = activeMap.fields
          .filter(f => f.sources && f.sources.COA && (f.type==='coa_lookup'||f.type==='coa_derived'))
          .map(f => f.label).join(', ');
        const span = coaMasterWarn.querySelector('span:last-child');
        if (span) span.innerHTML = 'COA Master not loaded — fields <strong>' + affectedFields + '</strong> will show <em>null</em> on the COA side.';
      }
    }
  }
}
/* =====================================================================
   COA ROW FILTERS — yellow (hierarchy) rows + 10-digit accounts
===================================================================== */
function isYellowish(hex){
  // hex = 6-char RRGGBB or 8-char AARRGGBB
  if(!hex||hex.length<6) return false;
  const h=hex.length===8?hex.slice(2):hex; // strip alpha
  if(h.length!==6) return false;
  const r=parseInt(h.slice(0,2),16);
  const g=parseInt(h.slice(2,4),16);
  const b=parseInt(h.slice(4,6),16);
  // Yellow range: high R, high G, low B
  return r>180&&g>160&&b<110;
}

function isYellowRow(ws,wsRowIdx){
  // Check first 5 columns only — fast and sufficient for row-level fills
  for(let c=0;c<5;c++){
    const addr=XLSX.utils.encode_cell({r:wsRowIdx,c});
    const cell=ws[addr];
    if(!cell||!cell.s) continue;
    const fg=cell.s.fgColor;
    if(fg&&fg.rgb&&isYellowish(fg.rgb.toUpperCase())) return true;
    const bg=cell.s.bgColor;
    if(bg&&bg.rgb&&isYellowish(bg.rgb.toUpperCase())) return true;
  }
  return false;
}

function isStrikeRow(ws,wsRowIdx){
  // A row is considered struck out if ANY cell in the first 10 columns has
  // strikethrough formatting (cell.s.strike === true in SheetJS cellStyles).
  // Checking 10 cols covers the account-key column in any typical COA layout.
  for(let c=0;c<10;c++){
    const addr=XLSX.utils.encode_cell({r:wsRowIdx,c});
    const cell=ws[addr];
    if(cell&&cell.s&&cell.s.strike===true) return true;
  }
  return false;
}

function getFilteredCOARows(){
  // ── Source: always S.refWbs.COA_MASTER (COA is a reference file in v6, not S.wbs.COA)
  const wb = S.refWbs.COA_MASTER;
  if(!wb) return [];

  const mapping = S.activeMapping || getEmbeddedMap();
  const cfg = mapping.reference_files && mapping.reference_files.COA_MASTER;
  const shIdx = (cfg && cfg.sheet_index != null) ? cfg.sheet_index : 0;
  const ws  = wb.Sheets[wb.SheetNames[shIdx]];
  if(!ws) return [];

  const allRows = XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});
  const headerRow = (cfg && cfg.header_row != null) ? cfg.header_row : 0;
  const headers = (allRows[headerRow]||[]).map(h=>h==null?'':String(h));
  const hdrIdx  = new Map();
  headers.forEach((h,i)=>{ const n=normHdr(h); if(n&&!hdrIdx.has(n)) hdrIdx.set(n,i); });
  const dataRows = allRows.slice(headerRow+1);

  // ── Locate "7 digit / 10 digit Accounts" column for the 10-digit filter.
  // chart_of_account is a coa_derived field; the source column lives in its
  // derivation conditions as source_col "7 digit  10 digit Accounts".
  const chartField = S.resolvedMap.find(f=>f.canonical==='chart_of_account'); // no trailing 's'
  let chartIdx = -1;
  if(chartField && chartField.sources.COA){
    const coaSrc = chartField.sources.COA;
    // derivation-type field: pull source_col from first condition
    if(coaSrc.derivation && coaSrc.derivation.conditions && coaSrc.derivation.conditions.length){
      const srcCol = coaSrc.derivation.conditions[0].source_col || '';
      chartIdx = hdrIdx.has(normHdr(srcCol)) ? hdrIdx.get(normHdr(srcCol)) : -1;
    } else if(typeof coaSrc.column === 'string'){
      chartIdx = coaColIdx(coaSrc, hdrIdx, headers);
    }
  }

  const doYellow   = S.skipYellow   && !!ws;
  const doTenDigit = S.skipTenDigit && chartIdx >= 0;
  const doStrike   = S.skipStrike   && !!ws;

  let yellowSkipped=0, tenDigitSkipped=0, strikeSkipped=0;
  const kept=[];

  dataRows.forEach((row,i)=>{
    // wsRowIdx: +1 for header row, +headerRow for any leading rows before header
    const wsRowIdx = i + headerRow + 1;

    // Yellow / hierarchy rows
    if(doYellow && isYellowRow(ws, wsRowIdx)){
      yellowSkipped++;
      return;
    }
    // 10-digit accounts only (skip 7-digit / non-10-digit)
    if(doTenDigit){
      const val = String(row[chartIdx]||'').toLowerCase().trim();
      if(!val.includes('10 digit')){
        tenDigitSkipped++;
        return;
      }
    }
    // Strikethrough — struck-out rows are retired accounts
    if(doStrike && isStrikeRow(ws, wsRowIdx)){
      strikeSkipped++;
      return;
    }
    kept.push(row.map(v=>v==null?'':String(v)));
  });

  S.coaFilterStats={total:dataRows.length,yellowSkipped,tenDigitSkipped,strikeSkipped,kept:kept.length};
  updateCoaFilterStats();
  return kept;
}

function updateCoaFilterStats(){
  const el=id('coaFilterStats');
  if(!el) return;
  const s=S.coaFilterStats;
  if(!s.total){el.textContent='';return;}
  el.innerHTML=
    '<strong>'+s.total.toLocaleString()+'</strong> total rows &rarr; '+
    (s.yellowSkipped?'<span style="background:#FFF8C5;color:#7D4E00;padding:1px 7px;border-radius:10px;font-weight:600;">'+s.yellowSkipped.toLocaleString()+' yellow skipped</span> &rarr; ':'&mdash; 0 yellow &rarr; ')+
    (s.tenDigitSkipped?'<span style="background:#FFE5D0;color:#7D4E00;padding:1px 7px;border-radius:10px;font-weight:600;">'+s.tenDigitSkipped.toLocaleString()+' non-10-digit skipped</span> &rarr; ':'')+
    (s.strikeSkipped?'<span style="background:#F3F0FF;color:#5B21B6;padding:1px 7px;border-radius:10px;font-weight:600;text-decoration:line-through;">'+s.strikeSkipped.toLocaleString()+'</span><span style="color:#5B21B6;font-weight:600;"> strikethrough skipped</span> &rarr; ':'')+
    '<strong style="color:var(--add-src)">'+s.kept.toLocaleString()+' rows used</strong>';
}


/* =====================================================================
   MAPPING RESOLUTION  (v5 — handles object COA sources for SKB types)
===================================================================== */
function buildResolvedMap() {
  const mapping = S.activeMapping || getEmbeddedMap();
  const isSKB   = mapping.comparison_grain === 'account_company_code';

  // Filter out skip fields
  const fields  = mapping.fields.filter(f =>
    !['dp_only','dp_internal'].includes(f.type) && f.comparison_rule !== 'skip'
  );

  S.resolvedMap = fields.map(field => {
    const resolved = JSON.parse(JSON.stringify(field));

    if (isSKB) {
      // COA source is an object (reference metadata) — keep as-is, no fuzzy matching
      // FAQ + DataPool sources are column names — fuzzy match against uploaded headers
      ['FAQ','DataPool'].forEach(src => {
        const col = field.sources[src];
        if (!col || typeof col !== 'string') { resolved.sources[src] = null; return; }
        const hdrs = S.headers[src];
        if (!hdrs.length) { resolved.sources[src] = col; return; }
        resolved.sources[src] = findBestCol(col, hdrs) || null;
      });
    } else {
      // SKA mode: COA source is an object (reference metadata, same as SKB) — keep as-is.
      // FAQ + DataPool sources are column name strings — fuzzy match against uploaded headers.
      ['FAQ','DataPool'].forEach(src => {
        const col = field.sources[src];
        if (!col || typeof col !== 'string') { resolved.sources[src] = null; return; }
        const hdrs = S.headers[src];
        if (!hdrs.length) { resolved.sources[src] = col; return; }
        resolved.sources[src] = findBestCol(col, hdrs) || null;
      });
      // COA: keep the reference metadata object (or null) as-is — no fuzzy matching needed
      resolved.sources['COA'] = field.sources['COA'] ?? null;
    }

    return resolved;
  });

  // Determine comparable fields
  const ccLoaded   = !!S.refWbs.CC_MATRIX;
  const txLoaded   = TX_SOURCES.filter(s => S.wbs[s] && S.activeSources.has(s));

  S.comparableFields = S.resolvedMap.filter(f => {
    if (S.excludedFields.has(f.canonical)) return false;
    if (isSKB) {
      const coaOk = f.sources.COA !== null && ccLoaded;
      const txOk  = txLoaded.filter(s => f.sources[s]).length;
      return (coaOk ? 1 : 0) + txOk >= 2;
    } else {
      // SKA: COA comes from S.refWbs.COA_MASTER, not S.wbs['COA']
      const coaOk = f.sources.COA !== null;
      const txLoaded2 = TX_SOURCES.filter(s => S.wbs[s] && S.activeSources.has(s));
      const txOk = txLoaded2.filter(s => f.sources[s]).length;
      return (coaOk ? 1 : 0) + txOk >= 2;
    }
  });
}

