function rfUpdateCols(rfid, src){
  const sel=document.getElementById('rfc-'+rfid);
  if(!sel) return;
  sel.innerHTML=(S.headers[src]||[]).map(h=>'<option value="'+esc(h)+'">'+esc(h)+'</option>').join('');
}

function removeRowFilter(rfid){
  const el=document.getElementById('rf-'+rfid);
  if(el) el.remove();
  S.rowFilters=S.rowFilters.filter(r=>r.id!==rfid);
  const list=document.getElementById('rowFilterList');
  if(!list.children.length) list.innerHTML='<span style="font-size:11px;color:var(--text3);font-style:italic;">No filters — all rows will be compared.</span>';
}

function getActiveRowFilters(){
  const chips=document.querySelectorAll('.rf-chip');
  const filters=[];
  chips.forEach(chip=>{
    const sels=chip.querySelectorAll('select');
    const inp=chip.querySelector('input');
    if(sels.length>=3&&inp&&inp.value.trim()){
      filters.push({src:sels[0].value, col:sels[1].value, op:sels[2].value, val:inp.value.trim()});
    }
  });
  return filters;
}

function passesRowFilters(src, row, filters){
  if(!filters.length) return true;
  return filters.every(f=>{
    if(f.src!==src) return true;
    const hi=S.headers[src].indexOf(f.col);
    if(hi<0) return true;
    const cell=(row[hi]||'').toLowerCase();
    const fv=f.val.toLowerCase();
    if(f.op==='contains') return cell.includes(fv);
    if(f.op==='equals') return cell===fv;
    if(f.op==='starts') return cell.startsWith(fv);
    if(f.op==='notcontains') return !cell.includes(fv);
    return true;
  });
}

/* =====================================================================
   MAPPING FILE UPLOAD
===================================================================== */
function loadMappingFile(file){
  if(!file) return;
  const r=new FileReader();
  r.onload=e=>{
    try{
      const parsed=JSON.parse(e.target.result);
      if(!parsed.fields||!Array.isArray(parsed.fields)) throw new Error('Missing "fields" array');
      S.activeMapping=parsed;
      const jdn=id('jsonDropName'); if(jdn){jdn.textContent='\uD83D\uDCC4 '+file.name+' ('+parsed.fields.length+' fields)';jdn.style.display='block';}
      const jrb=id('jsonResetBtn'); if(jrb) jrb.style.display='';
      const jd=id('jsonDrop'); if(jd) jd.classList.add('loaded');
      // Sync compact drop in mapping tab
      const sm=id('jsonDropSm'); if(sm) sm.classList.add('loaded');
      const sml=id('jsonDropSmLabel'); if(sml) sml.textContent=file.name;
      const smr=id('jsonResetBtnSm'); if(smr) smr.style.display='';
      showToast('Mapping loaded: '+parsed.fields.length+' fields','ok');
    }catch(err){
      showToast('Invalid mapping JSON: '+err.message,'err');
    }
  };
  r.readAsText(file);
}

function resetMapping(e){
  e.stopPropagation();
  S.activeMapping=null;
  const jdn=id('jsonDropName'); if(jdn){jdn.style.display='none';}
  const jrb=id('jsonResetBtn'); if(jrb) jrb.style.display='none';
  const jd=id('jsonDrop'); if(jd) jd.classList.remove('loaded');
  const sm=id('jsonDropSm'); if(sm) sm.classList.remove('loaded');
  const sml=id('jsonDropSmLabel'); if(sml) sml.textContent='Mapping JSON';
  const smr=id('jsonResetBtnSm'); if(smr) smr.style.display='none';
  showToast('Mapping reset to embedded SKA defaults','ok');
}

/* =====================================================================
   COLUMN EXCLUDE / RE-INCLUDE
===================================================================== */
function toggleExclude(canonical){
  if(S.excludedFields.has(canonical)){
    S.excludedFields.delete(canonical);
    showToast('Field re-included — re-run Compare to apply','ok');
  } else {
    S.excludedFields.add(canonical);
    showToast('Field excluded — re-run Compare to apply','warn');
  }
  // Do NOT recompute S.comparableFields here — it is the stable index
  // reference for _diffRows.vals. Only runDiff() may set it.
  refreshMapMeta();
  refreshCompareHint();
  renderMappingTable();
  // If results are visible, refresh the restore bar
  if(id('subtab-panel-results')&&id('subtab-panel-results').classList.contains('active')) renderExclBar();
}

function hideColFromResults(canonical){
  S.hiddenCols.add(canonical);
  // Mark excluded so the next re-run skips it — but do NOT touch S.comparableFields
  // here because _diffRows.vals are indexed against the original comparableFields order
  S.excludedFields.add(canonical);
  const f=S.resolvedMap.find(r=>r.canonical===canonical);
  showToast('Column hidden: '+(f?f.label:canonical)+' \u2014 re-run to update match counts','warn');
  S.pageOffset=0;
  renderDiff(true);
  renderExclBar();
}

function restoreCol(canonical){
  S.hiddenCols.delete(canonical);
  S.excludedFields.delete(canonical);
  const f=S.resolvedMap.find(r=>r.canonical===canonical);
  showToast('Column restored: '+(f?f.label:canonical),'ok');
  S.pageOffset=0;
  renderDiff(true);
  renderExclBar();
}

function renderExclBar(){
  const bar=id('exclBar'), pills=id('exclPills');
  if(!bar||!pills) return;
  const allHidden=new Set([...S.excludedFields,...S.hiddenCols]);
  if(!allHidden.size){bar.classList.add('hidden');return;}
  bar.classList.remove('hidden');
  const fieldLabels={};
  S.resolvedMap.forEach(f=>{fieldLabels[f.canonical]=f.label;});
  pills.innerHTML=[...allHidden].map(c=>{
    const isHidden=S.hiddenCols.has(c);
    return '<span class="excl-pill" onclick="'+(isHidden?'restoreCol':'toggleExclude')+'(\''+esc(c)+'\')" title="Click to restore">'+
      esc(fieldLabels[c]||c)+(isHidden?' \uD83D\uDC41 \u21a9':' \u21a9')+
      '</span>';
  }).join('');
}

